const body = $input.first().json.body;

let payload;
try {
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
} catch(e) {
  throw new Error('Payload Slack inválido: ' + e.message);
}

const action = payload.actions?.[0];
const actionId = action?.action_id || '';
const actionValue = action?.value || '';
const userId = payload.user?.id || 'desconocido';
const userName = payload.user?.username || payload.user?.name || 'desconocido';
const messageTs = payload.message?.ts || '';
const channelId = payload.channel?.id || '';

let tipoAccion = 'desconocida';
if (actionId === 'aprobar_comunicacion' || actionId.startsWith('aprobar_')) tipoAccion = 'aprobar';
else if (actionId === 'rechazar_comunicacion' || actionId.startsWith('rechazar_')) tipoAccion = 'rechazar';
else if (actionId === 'falso_positivo' || actionId.startsWith('fp_')) tipoAccion = 'false_positive';
else if (actionId === 'pausar_alertas') tipoAccion = 'pausar';
else if (actionId === 'ver_cola_aprobacion') tipoAccion = 'ver_cola';
else if (actionId === 'abrir_dashboard') tipoAccion = 'abrir_dashboard';
else if (actionId === 'recalibrar_aplicar') tipoAccion = 'recalibrar_aplicar';
else if (actionId === 'recalibrar_ignorar') tipoAccion = 'recalibrar_ignorar';

const idEntidad = actionValue.replace(/^(aprobar_|rechazar_|fp_)/, '') || actionValue;

return [{
  json: {
    tipo_accion: tipoAccion,
    action_id: actionId,
    id_entidad: idEntidad,
    user_id: userId,
    user_name: userName,
    message_ts: messageTs,
    channel_id: channelId
  }
}];

