const items = $input.all();
const user = $('Parsear y Validar Payload Slack').first().json.user_name;

if (items.length === 0 || !items[0].json.id) {
  return [{
    json: {
      slack_blocks: [
        { type: 'section', text: { type: 'mrkdwn', text: `*📋 Cola de aprobaciones — solicitada por @${user}*\n\nNo hay alertas altas/críticas abiertas en este momento. 🎉` } }
      ]
    }
  }];
}

const fmtPct = (n) => n !== null && n !== undefined ? `${Number(n) > 0 ? '+' : ''}${Number(n).toFixed(1)}%` : 'N/D';

const header = { type: 'section', text: { type: 'mrkdwn', text: `*📋 Cola de aprobaciones — ${items.length} alerta(s) — solicitada por @${user}*` } };
const divider = { type: 'divider' };

const alertBlocks = [];
for (const it of items) {
  const a = it.json;
  const sev = a.severidad === 'critica' ? '🔴' : '🟠';
  const narrativa = (a.narrativa_corta || '').substring(0, 140);
  alertBlocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `${sev} *${a.contratista_nombre || 'Contratista'}* — ${a.zona || 'zona'} — ${a.codigo_alerta}\n${narrativa} _(${fmtPct(a.delta_pct)})_` }
  });
  alertBlocks.push({
    type: 'actions',
    elements: [
      { type: 'button', text: { type: 'plain_text', text: 'Aprobar' }, action_id: `aprobar_${a.id}`, style: 'primary', value: `aprobar_${a.id}` },
      { type: 'button', text: { type: 'plain_text', text: 'Falso positivo' }, action_id: `fp_${a.id}`, style: 'danger', value: `fp_${a.id}` }
    ]
  });
}

return [{
  json: {
    slack_blocks: [header, divider, ...alertBlocks]
  }
}];
